import React from "react";
import { Dropdown, style } from "@lmb-it/kitsconcertomobile";
import type { IDropdownSelect } from "@lmb-it/kitsconcerto-types";
import { KitsContainer } from "../../../../index";
import { ClHelper } from "../../Helpers/Functions";
import { useSelectBase } from "../hooks/useSelectBase";
import {useComponentDefaults} from "@lmb-it/kitsconcerto/Hooks";

const KitsDropdown = ({ className, ref, ...rawProps }: IDropdownSelect) => {
    const {mergedProps: props, themeStyle} = useComponentDefaults('DropdownSelect', rawProps, 'Select');
    const {
        id,
        rightAddon,
        leftAddon,
        errors,
        invalid,
        disabled,
        required,
        label,
        localProps,
        helperText,
        isFloatedLabel,
        withFilter,
        attached,
        inputSize,
        placeholder,
        hideError,
        virtualScroll,
        emptyFilterMessage,
        filterBy,
        loading,
        showClear,
    } = props;

    const { list, keys, onChange, selectedValue } = useSelectBase();

    const ClState = ClHelper({
        inputSize: inputSize ?? "",
        isChecked: false,
        isInvalid: !!invalid,
        isDisabled: !!disabled,
    });

    const dropdownValue = selectedValue != null && typeof selectedValue !== 'object'
        ? selectedValue.toString()
        : selectedValue;

    const Element = (
        <Dropdown
            emptyFilterMessage={emptyFilterMessage}
            value={dropdownValue}
            placeholder={placeholder}
            options={Array.isArray(list) ? list : []}
            disabled={disabled}
            loading={loading}
            showClear={showClear ?? (!required && selectedValue != null)}
            style={{ width: '100%', height: attached ? '100%' : undefined, ...(Object.keys(themeStyle).length ? style(themeStyle) : {}) }}
            onChange={onChange}
            {...keys}
            invalid={hideError && !!invalid}
            filter={!!withFilter}
            filterBy={filterBy}
            virtualScrollerOptions={virtualScroll}
            className={`w-full ${className ?? ''} ${ClState}`}
            {...(localProps ? localProps : {})}
        />
    );

    if (attached) {
        return Element;
    }

    return (
        <KitsContainer
            id={id}
            inputSize={inputSize}
            isFloatedLabel={isFloatedLabel}
            rightAddon={rightAddon}
            leftAddon={leftAddon}
            required={required}
            hideError={hideError}
            errors={errors}
            helperText={helperText}
            invalid={invalid}
            label={label}
        >
            {Element}
        </KitsContainer>
    );
}
export default KitsDropdown;
